import React from 'react';
import './Section.css';
import Article from "../Article.js";
import { ArticleChoices } from "../ArticleChoices.js";

class Section extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
        expanded: true,
    }
    this.handleClick = this.handleClick.bind(this)
  }

  handleClick() {
      this.setState(state => ({
          expanded: !this.state.expanded,
      }));
      this.collapse();
  }

  test(a) {
    return (
        <div>
            {ArticleChoices[0].map(items => (
              <div className='content-holder'>
                <div id='descriptions'>
                    <p>{items.descr}</p>
                </div>
                <div id='stories'>
                    <Article index={items.story} />
                </div>
              </div>
            ))}
        </div>

    )
  }

  render() {
    return (
      <div className='outer'>
          <div id='topBar'>
             <h2>{this.props.title}</h2>
          </div>
          {this.test(this.props.index)}
      </div>
    );
  }
}

const Portfolio = () => {
    return (
        <div id='portfolio'>
            <Section title='Reporting on UCLA student at the U.S. Capitol riots' index={0}/>
            <Section title='Data reporting' index={1}/>
        </div>
    );
}

export default Portfolio;
